const QUICKGUIDE_DATA = {"categories": [{"id": "ob-lost", "icon": "🚫", "title": "OB・紛失球", "color": "#e74c3c", "situations": [{"question": "球がOBに行った", "answer": "ストロークと距離の罰：1罰打を加え、前回のストロークを行った場所からプレー。", "rule": "18.2", "procedure": "1. 前回打った場所に戻る\n2. 1罰打を加える\n3. その場所からプレー\n※ ローカルルールで前進2打罰の選択肢がある場合もある"}, {"question": "球が見つからない（紛失球）", "answer": "捜索開始から3分以内に見つからなければ紛失球。ストロークと距離の罰。", "rule": "18.2", "procedure": "1. 捜索は3分間まで\n2. 見つからなければ紛失球\n3. 1罰打を加え、前回の場所からプレー"}, {"question": "暫定球を打ちたい", "answer": "元の球がOBまたは紛失の可能性がある場合、暫定球を打てる（ペナルティーエリアは不可）。", "rule": "18.3", "procedure": "1. 「暫定球を打ちます」と宣言\n2. 前回の場所から暫定球をプレー\n3. 元の球が見つかればその球でプレー\n4. 元の球が紛失/OBなら暫定球でプレー（1罰打）"}, {"question": "暫定球を元の球があると推定される場所より先からプレーした", "answer": "暫定球がインプレーの球となり、元の球は紛失球として扱われる。", "rule": "18.3c(2)", "procedure": "1. 暫定球が新しいインプレーの球\n2. 元の球が見つかっても、もうプレーできない\n3. 暫定球でプレーを続ける"}]}, {"id": "penalty-area", "icon": "🔴", "title": "ペナルティーエリア", "color": "#e67e22", "situations": [{"question": "球が黄杭のペナルティーエリアに入った", "answer": "1罰打で3つの選択肢がある。", "rule": "17.1", "procedure": "選択肢（各1罰打）：\n1. ストロークと距離：前回の場所からプレー\n2. 後方線上の救済：球がペナルティーエリアの縁を最後に横切った地点とホールを結ぶ線上で、後方にドロップ"}, {"question": "球が赤杭のペナルティーエリアに入った", "answer": "1罰打で黄の選択肢に加え、ラテラル救済が可能。", "rule": "17.1d", "procedure": "選択肢（各1罰打）：\n1. ストロークと距離：前回の場所からプレー\n2. 後方線上の救済\n3. ラテラル救済：球がペナルティーエリアの縁を最後に横切った地点から2クラブレングス以内にドロップ（ホールに近づかない）"}, {"question": "ペナルティーエリア内からプレーしたい", "answer": "罰なしでそのまま打てる。ただし地面やwater にクラブを触れてはならないなどの制限はない（2019年改訂で制限撤廃）。", "rule": "17.1a", "procedure": "1. あるがままにプレー可能\n2. 2019年規則改訂によりソールやテストの制限は撤廃\n3. ルースインペディメントも取り除ける"}]}, {"id": "bunker", "icon": "⛳", "title": "バンカー", "color": "#f39c12", "situations": [{"question": "バンカー内で砂に触れてよいか", "answer": "ストロークの直前にバックスイングで砂に触れることは禁止。それ以外の合理的な行動は認められる。", "rule": "12.2b", "procedure": "禁止されること：\n・砂の状態をテストすること\n・練習スイングで砂に触れること\n・バックスイングで砂に触れること\n\n認められること：\n・クラブを砂の上に軽く置くこと\n・バンカーの中を歩くこと\n・怒ってクラブで砂を叩くこと（ストロークに影響を改善しない場合）"}, {"question": "バンカー内の球をアンプレヤブルにしたい", "answer": "3つの選択肢（バンカー内）+ バンカー外に出す選択肢（2罰打）。", "rule": "19.3", "procedure": "バンカー内（各1罰打）：\n1. ストロークと距離：前回の場所からプレー\n2. 後方線上の救済（バンカー内に限る）\n3. ラテラル救済：2クラブレングス以内（バンカー内に限る）\n\nバンカー外（2罰打）：\n4. 球とホールを結ぶ後方線上で、バンカー外にドロップ"}, {"question": "バンカー内のルースインペディメントを取り除ける？", "answer": "はい。2019年規則改訂により、バンカー内のルースインペディメント（木の葉、石など）を罰なしに取り除ける。", "rule": "12.2a, 15.1", "procedure": "バンカー内でも罰なしでルースインペディメントを取り除ける（2019年改訂）"}]}, {"id": "green", "icon": "🏌️", "title": "パッティンググリーン", "color": "#27ae60", "situations": [{"question": "グリーン上で球をマーク・拾い上げてよいか", "answer": "パッティンググリーン上の球はいつでもマークして拾い上げ、ふくことができる。", "rule": "13.1b", "procedure": "1. 球の直後または直横にマーカーを置く\n2. 球を拾い上げる\n3. 球をふくことができる\n4. リプレースする際はマーカーの前に置く"}, {"question": "グリーン上の損傷を修理してよいか", "answer": "ほぼすべての損傷を修理できる。スパイクマーク、ボールマーク、動物の足跡など。", "rule": "13.1c", "procedure": "修理できるもの：\n・ボールマーク\n・スパイクマーク\n・動物の足跡\n・用具やティーの刺し跡\n・旗竿の損傷\n\n修理できないもの：\n・自然な凹凸や摩耗\n・ホールの自然な表面\n・エアレーションの穴"}, {"question": "旗竿は立てたままパットしてよいか", "answer": "はい。旗竿を立てたまま、付き添ってもらう、取り除くのいずれも選択できる。グリーン上から打って旗竿に当たっても罰はない。", "rule": "13.2a", "procedure": "プレーヤーの選択：\n1. 旗竿をそのまま立てておく\n2. 旗竿を取り除く\n3. 誰かに付き添ってもらう\n\n※ 2019年改訂：グリーン上から打って旗竿に当たっても罰なし"}, {"question": "グリーン上で他のプレーヤーの球に当たった", "answer": "ストロークプレー：両者とも罰なし。グリーン上からプレーした場合、ストロークの再プレーが必要。", "rule": "11.1a", "procedure": "ストロークプレー：\n・当てた側：パッティンググリーン上からプレーした場合→ストローク取消、再プレー\n・当てられた側：元の位置にリプレース\n\nマッチプレー：\n・罰なし、球はあるがままにプレー"}]}, {"id": "ball-moved", "icon": "⚡", "title": "球が動いた", "color": "#9b59b6", "situations": [{"question": "アドレス後に球が動いた", "answer": "プレーヤーが原因でない場合は罰なしでリプレース。プレーヤーが原因の場合は1罰打でリプレース。", "rule": "9.4", "procedure": "1. プレーヤーが球を動かした場合：1罰打、元の位置にリプレース\n2. 自然の力（風など）で動いた場合：罰なし、新しい位置からプレー\n3. 原因が分からない場合：プレーヤーが動かした可能性が高い場合は9.4を適用"}, {"question": "球を捜索中に球を動かしてしまった", "answer": "罰なし。元の位置にリプレース（推定でよい）。", "rule": "7.4", "procedure": "1. 罰なし\n2. 球を元の推定位置にリプレース\n3. 球が見つからない場合は紛失球の処置"}, {"question": "風で球が動いた", "answer": "自然の力が原因。新しい位置からプレーする（リプレースしない）。", "rule": "9.3", "procedure": "1. 罰なし\n2. 球が止まった新しい位置からプレー\n※ ただし、救済を受けた後やリプレースした後に自然の力で動いた場合は元の位置にリプレース"}, {"question": "練習スイングで球が動いた", "answer": "プレーヤーが球を動かしたことになる。1罰打でリプレース。", "rule": "9.4b", "procedure": "1. 1罰打\n2. 元の位置にリプレース\n3. リプレースしないでプレーすると誤所からのプレー"}]}, {"id": "relief", "icon": "🔄", "title": "救済（罰なし）", "color": "#3498db", "situations": [{"question": "カート道路に球がある、またはスタンスがかかる", "answer": "動かせない障害物からの罰なしの救済。完全な救済のニヤレストポイントを基点に1クラブレングス以内にドロップ。", "rule": "16.1", "procedure": "1. 完全な救済のニヤレストポイントを決定\n   （球のライ、スタンス、スイング区域で障害物の影響がない最も近い地点）\n2. その地点から1クラブレングスの救済エリアにドロップ\n3. ホールに近づかない\n4. 同じコースエリア内"}, {"question": "修理地に球がある", "answer": "異常なコース状態からの罰なしの救済。", "rule": "16.1", "procedure": "1. 完全な救済のニヤレストポイントを決定\n2. 1クラブレングスの救済エリアにドロップ\n3. ホールに近づかない、同じコースエリア内"}, {"question": "一時的な水（カジュアルウォーター）に球がある", "answer": "異常なコース状態からの罰なしの救済。", "rule": "16.1", "procedure": "1. 完全な救済のニヤレストポイントを決定\n2. 1クラブレングスの救済エリアにドロップ\n3. スタンスを取った時に水が見えなくなる場所"}, {"question": "球が地面にくい込んだ（埋まった）", "answer": "ジェネラルエリアで球が地面にくい込んだ場合、罰なしの救済。", "rule": "16.3", "procedure": "1. 球の直後の地点を基点\n2. 1クラブレングスの救済エリアにドロップ\n3. ジェネラルエリアに限る\n4. ホールに近づかない\n※ バンカー、ペナルティーエリアでは適用されない"}]}, {"id": "drop", "icon": "🖐️", "title": "ドロップの手順", "color": "#1abc9c", "situations": [{"question": "正しいドロップの方法は？", "answer": "膝の高さから球を落とす。真下に落とし、体や用具に当たらないようにする。", "rule": "14.3b", "procedure": "1. 救済エリアを決定\n2. 膝の高さから球を持つ\n3. 手を離して球を落とす（投げない、回転をかけない）\n4. 救済エリア内に止まればOK\n5. 救済エリア外に出たら再ドロップ\n6. 2回目も外に出たらプレース"}, {"question": "ドロップした球が救済エリアの外に出た", "answer": "再ドロップする。2回目も外に出たら、2回目に地面に最初に触れた地点にプレースする。", "rule": "14.3c", "procedure": "1回目ドロップ→エリア外：再ドロップ\n2回目ドロップ→エリア外：2回目に球が最初に地面に触れた地点にプレース"}, {"question": "後方線上の救済の手順", "answer": "基点とホールを結ぶ線上の後方にドロップ。球が最初に地面に触れた地点から1クラブレングスが救済エリア。", "rule": "14.3b(3)", "procedure": "1. 基点（ペナルティーエリアの縁を最後に横切った地点など）とホールを結ぶ線を延長\n2. その線上のどこかにドロップ\n3. 球が最初に地面に触れた地点を中心に1クラブレングスが救済エリア\n4. ホールに近づかない\n※ 2023年改訂で手続きが簡素化"}]}, {"id": "equipment", "icon": "🏑", "title": "用具・クラブ", "color": "#34495e", "situations": [{"question": "ラウンド中にクラブが壊れた", "answer": "乱暴に扱ったのでなければ、そのクラブを修理、取り替え、またはそのまま使用できる（2023年改訂）。", "rule": "4.1a(2)", "procedure": "プレーヤーの選択（乱暴でない損傷の場合）：\n1. 損傷したまま使用する\n2. 修理する\n3. 別のクラブと取り替える\n※ 乱暴に扱った場合：使い続けるか、プレーから除外のみ（取り替え不可）"}, {"question": "14本を超えてクラブを持っている", "answer": "各ホール最大2罰打（ストロークプレー）。直ちにプレーから除外を宣言する。", "rule": "4.1b", "procedure": "1. 発覚次第、余分なクラブをプレーから除外することを宣言\n2. ストロークプレー：違反があった各ホールに2罰打（最大4罰打）\n3. マッチプレー：違反があった各ホールの結果を修正（最大2ホール差引）"}, {"question": "距離計測器は使えるか", "answer": "ローカルルールで禁止されていなければ使用可能。高低差機能は禁止されている場合が多い。", "rule": "4.3a", "procedure": "・距離のみの計測：認められる（ローカルルールで禁止されていない限り）\n・高低差機能：ローカルルールで禁止可能\n・風速計、傾斜計等の機能：使用禁止"}]}, {"id": "committee", "icon": "📋", "title": "競技委員の判断", "color": "#2c3e50", "situations": [{"question": "プレーヤーから裁定を求められた", "answer": "レフェリーが対応できる場合はレフェリーの裁定が最終。委員会が対応する場合は規則に基づいて裁定。", "rule": "20.1", "procedure": "1. 事実を確認する\n2. 該当する規則を特定する\n3. 規則に基づいて裁定する\n4. プレーヤーに裁定を伝える\n※ 疑義がある場合、ストロークプレーでは2つの球でプレーを認める（規則20.1c(3)）"}, {"question": "プレーヤーが2つの球でプレーしたいと言っている", "answer": "ストロークプレーで規則の適用に疑義がある場合、2つの球でプレーを選択できる。", "rule": "20.1c(3)", "procedure": "1. プレーヤーはどちらの球のスコアをカウントしたいか宣言\n2. 宣言しない場合は、最初にプレーした球が自動的に選択\n3. 両方の球でホールを終了\n4. 委員会が裁定を下す\n5. 規則が認める球がカウントされる"}, {"question": "スロープレーのプレーヤーがいる", "answer": "不当の遅延に対して罰を課すことができる。", "rule": "5.6", "procedure": "1回目の違反：1罰打\n2回目の違反：一般の罰（2罰打）\n3回目の違反：失格\n\n※ 委員会がプレーのペースの方針を定めている場合はそれに従う"}, {"question": "雷が近づいている - プレーの中断", "answer": "委員会は危険のためにプレーを中断できる。即時中断（サイレン1回長音）の場合、プレーヤーは直ちにプレーを中止しなければならない。", "rule": "5.7", "procedure": "即時中断（危険な状況）：\n・サイレン1回長音で通知\n・プレーヤーは直ちにプレーを中止\n・中断中にプレーした場合：失格\n\n通常中断：\n・プレーヤーはそのホールを終了してから中断可能\n\n再開：\n・委員会が再開を指示\n・中断した箇所からプレー再開"}]}]};
